// Entry Validation Node - Validates and sanitizes form data
const body = $input.first().json.body;
const result = { valid: true, errors: [], warnings: [], normalized: {}, original: body };

const validateEmail = (email) => {
  if (!email || typeof email !== 'string') return { valid: false, reason: 'Email is required' };
  const trimmed = email.trim().toLowerCase();
  if (trimmed.length === 0) return { valid: false, reason: 'Email is empty' };
  if (trimmed.length > 254) return { valid: false, reason: 'Email too long' };
  if (!trimmed.includes('@')) return { valid: false, reason: 'Missing @ symbol' };
  const [local, domain] = trimmed.split('@');
  if (!local || local.length === 0) return { valid: false, reason: 'Local part empty' };
  if (local.length > 64) return { valid: false, reason: 'Local part too long' };
  if (local.startsWith('.') || local.endsWith('.')) return { valid: false, reason: 'Local part cannot start/end with dot' };
  if (local.includes('..')) return { valid: false, reason: 'Consecutive dots in local part' };
  if (!domain || domain.length === 0) return { valid: false, reason: 'Domain empty' };
  if (!domain.includes('.')) return { valid: false, reason: 'Missing TLD' };
  const tld = domain.substring(domain.lastIndexOf('.') + 1);
  if (tld.length < 2) return { valid: false, reason: 'TLD too short' };
  const emailRegex = /^[a-z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?(?:\.[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?)*$/;
  if (!emailRegex.test(trimmed)) return { valid: false, reason: 'Invalid email format' };
  return { valid: true, normalized: trimmed };
};

const parseFullName = (fullName) => {
  if (!fullName || typeof fullName !== 'string') return { firstName: 'Unknown', lastName: '', prefix: '', suffix: '' };
  const clean = fullName.trim().replace(/\s+/g, ' ');
  if (clean.length === 0) return { firstName: 'Unknown', lastName: '', prefix: '', suffix: '' };
  const prefixes = ['Dr.', 'Dr', 'Mr.', 'Mr', 'Mrs.', 'Mrs', 'Ms.', 'Ms', 'Prof.', 'Prof'];
  const suffixes = ['Jr.', 'Jr', 'Sr.', 'Sr', 'II', 'III', 'IV', 'V', 'PhD', 'MD'];
  let working = clean;
  let prefix = '';
  let suffix = '';
  for (const p of prefixes) {
    if (working.startsWith(p + ' ')) {
      prefix = p.endsWith('.') ? p : p + '.';
      working = working.substring(p.length).trim();
      break;
    }
  }
  for (const s of suffixes) {
    if (working.endsWith(' ' + s)) {
      suffix = s;
      working = working.substring(0, working.length - s.length).trim();
      break;
    }
  }
  const parts = working.split(' ');
  if (parts.length === 1) {
    return { firstName: prefix ? `${prefix} ${parts[0]}` : parts[0], lastName: suffix, prefix, suffix };
  }
  const firstName = prefix ? `${prefix} ${parts[0]}` : parts[0];
  const lastName = suffix ? `${parts.slice(1).join(' ')} ${suffix}` : parts.slice(1).join(' ');
  return { firstName, lastName, prefix, suffix };
};

const sanitizeInput = (input, maxLength = 5000) => {
  if (!input || typeof input !== 'string') return '';
  let sanitized = input.replace(/<[^>]*>/g, '').replace(/[<>]/g, '').trim();
  if (sanitized.length > maxLength) sanitized = sanitized.substring(0, maxLength);
  return sanitized;
};

const validateCompany = (name) => {
  if (!name || typeof name !== 'string') return { valid: false, reason: 'Company name required' };
  const trimmed = name.trim();
  if (trimmed.length === 0) return { valid: false, reason: 'Company name empty' };
  if (trimmed.length < 2) return { valid: false, reason: 'Company name too short' };
  if (trimmed.length > 255) return { valid: false, reason: 'Company name too long' };
  if (!/[a-zA-Z]/.test(trimmed)) return { valid: false, reason: 'Must contain letters' };
  return { valid: true, normalized: trimmed };
};

const validatePhone = (phone) => {
  if (!phone || typeof phone !== 'string') return { valid: false, reason: 'Invalid phone' };
  const digits = phone.replace(/\D/g, '');
  if (digits.length < 10) return { valid: false, reason: 'Too few digits' };
  if (digits.length > 15) return { valid: false, reason: 'Too many digits' };
  const normalized = digits.length === 10 ? '+1' + digits : '+' + digits;
  return { valid: true, normalized };
};

const data = body.data || body;

const emailField = data.email || data.Email;
const emailResult = validateEmail(emailField);
if (!emailResult.valid) {
  result.valid = false;
  result.errors.push({ field: 'email', message: emailResult.reason, code: 'INVALID_EMAIL' });
} else {
  result.normalized.email = emailResult.normalized;
}

const nameField = data.name || data.fullName || data.full_name;
if (nameField) {
  const nameParts = parseFullName(nameField);
  result.normalized.firstName = nameParts.firstName;
  result.normalized.lastName = nameParts.lastName;
  result.normalized.namePrefix = nameParts.prefix;
  result.normalized.nameSuffix = nameParts.suffix;
} else {
  result.warnings.push({ field: 'name', message: 'Name not provided' });
  result.normalized.firstName = 'Unknown';
  result.normalized.lastName = '';
}

const companyField = data.company || data.companyName;
if (companyField) {
  const companyResult = validateCompany(companyField);
  if (!companyResult.valid) {
    result.warnings.push({ field: 'company', message: companyResult.reason });
    result.normalized.company = sanitizeInput(companyField, 255) || 'Unknown Company';
  } else {
    result.normalized.company = companyResult.normalized;
  }
} else {
  result.normalized.company = 'Unknown Company';
}

const phoneField = data.phone || data.phoneNumber;
if (phoneField) {
  const phoneResult = validatePhone(phoneField);
  if (!phoneResult.valid) {
    result.warnings.push({ field: 'phone', message: phoneResult.reason });
  } else {
    result.normalized.phone = phoneResult.normalized;
  }
}

result.normalized.jobTitle = sanitizeInput(data.role || data.jobTitle || data.title, 255);
result.normalized.message = sanitizeInput(data.message || data.notes, 10000);
result.normalized.teamSize = sanitizeInput(data.teamSize, 50);
result.normalized.securityLevel = sanitizeInput(data.securityLevel, 100);

const formatArray = (arr) => {
  if (!arr) return '';
  if (Array.isArray(arr)) return arr.join(', ');
  if (typeof arr === 'string') return arr;
  return String(arr);
};
result.normalized.techStack = formatArray(data.techStack);
result.normalized.compliance = formatArray(data.compliance);
result.normalized._meta = { submittedAt: new Date().toISOString(), source: 'consultation_form_v3', validationVersion: '3.0.0' };

return [{ json: result }];

// Duplicate Detection Node
const input = $input.first().json;
const normalized = input.normalized;
const CRM_BASE_URL = $env.CRM_BASE_URL || 'https://crm.zaplit.com';
const CRM_API_TOKEN = $env.CRM_API_TOKEN;

const result = {
  hasDuplicates: false,
  person: { duplicate: false, record: null, id: null },
  company: { duplicate: false, record: null, id: null, matchScore: 0 },
  action: 'create',
  data: normalized
};

const levenshtein = (s1, s2) => {
  if (s1.length === 0) return s2.length;
  if (s2.length === 0) return s1.length;
  const matrix = [];
  for (let i = 0; i <= s2.length; i++) matrix[i] = [i];
  for (let j = 0; j <= s1.length; j++) matrix[0][j] = j;
  for (let i = 1; i <= s2.length; i++) {
    for (let j = 1; j <= s1.length; j++) {
      matrix[i][j] = s2[i-1] === s1[j-1] ? matrix[i-1][j-1] : Math.min(matrix[i-1][j] + 1, matrix[i][j-1] + 1, matrix[i-1][j-1] + 1);
    }
  }
  return matrix[s2.length][s1.length];
};

const similarity = (s1, s2) => {
  s1 = String(s1 || '').toLowerCase();
  s2 = String(s2 || '').toLowerCase();
  if (s1 === s2) return 1;
  const maxLen = Math.max(s1.length, s2.length);
  if (maxLen === 0) return 0;
  return (maxLen - levenshtein(s1, s2)) / maxLen;
};

const normalizeCompany = (name) => {
  if (!name) return '';
  return name.toLowerCase().replace(/\s*,?\s*(inc\.?|incorporated|corp\.?|corporation|llc|ltd\.?|limited)\s*$/i, '').replace(/[.,;:!?()[\]{}]/g, '').trim();
};

const fuzzyMatchCompany = (name1, name2) => {
  if (!name1 || !name2) return { score: 0, match: false };
  const orig1 = name1.trim();
  const orig2 = name2.trim();
  if (orig1.toLowerCase() === orig2.toLowerCase()) return { score: 1, match: true };
  const norm1 = normalizeCompany(orig1);
  const norm2 = normalizeCompany(orig2);
  if (norm1 === norm2 && norm1.length > 0) return { score: 0.95, match: true };
  const normSim = similarity(norm1, norm2);
  const origSim = similarity(orig1, orig2);
  let subScore = 0;
  if (norm1.length > 3 && norm2.length > 3) {
    if (norm1.includes(norm2) || norm2.includes(norm1)) {
      subScore = Math.min(norm1.length, norm2.length) / Math.max(norm1.length, norm2.length);
    }
  }
  const score = Math.max(normSim * 0.5 + origSim * 0.3 + subScore * 0.2, subScore * 0.9);
  return { score: Math.round(score * 100) / 100, match: score >= 0.85 };
};

const checkDuplicatePerson = async (email) => {
  if (!email || !CRM_API_TOKEN) return { duplicate: false };
  try {
    const response = await fetch(`${CRM_BASE_URL}/rest/people?filter=emails[contains]=${encodeURIComponent(email)}&limit=5`, {
      headers: { 'Authorization': `Bearer ${CRM_API_TOKEN}`, 'Content-Type': 'application/json' }
    });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const data = await response.json();
    if (data.data && data.data.length > 0) {
      for (const person of data.data) {
        const emails = person.emails || [];
        const exactMatch = emails.some(e => e.email?.toLowerCase().trim() === email.toLowerCase());
        if (exactMatch) return { duplicate: true, record: person, id: person.id, confidence: 'exact' };
      }
    }
    return { duplicate: false };
  } catch (error) {
    console.error('Person check failed:', error);
    return { duplicate: false, error: error.message };
  }
};

const checkDuplicateCompany = async (name) => {
  if (!name || !CRM_API_TOKEN) return { duplicate: false, matchScore: 0 };
  try {
    const exactResponse = await fetch(`${CRM_BASE_URL}/rest/companies?filter=name[eq]=${encodeURIComponent(name)}&limit=5`, {
      headers: { 'Authorization': `Bearer ${CRM_API_TOKEN}`, 'Content-Type': 'application/json' }
    });
    if (!exactResponse.ok) throw new Error(`HTTP ${exactResponse.status}`);
    const exactData = await exactResponse.json();
    if (exactData.data && exactData.data.length > 0) {
      const exact = exactData.data.find(c => c.name?.toLowerCase().trim() === name.toLowerCase());
      if (exact) return { duplicate: true, record: exact, id: exact.id, matchScore: 1, confidence: 'exact' };
    }
    const firstWord = name.split(' ')[0];
    const fuzzyResponse = await fetch(`${CRM_BASE_URL}/rest/companies?filter=name[ilike]=%${encodeURIComponent(firstWord)}%&limit=20`, {
      headers: { 'Authorization': `Bearer ${CRM_API_TOKEN}`, 'Content-Type': 'application/json' }
    });
    if (!fuzzyResponse.ok) throw new Error(`HTTP ${fuzzyResponse.status}`);
    const fuzzyData = await fuzzyResponse.json();
    if (fuzzyData.data && fuzzyData.data.length > 0) {
      let bestMatch = null;
      let bestScore = 0;
      for (const company of fuzzyData.data) {
        const match = fuzzyMatchCompany(name, company.name);
        if (match.score > bestScore) {
          bestScore = match.score;
          bestMatch = company;
        }
      }
      if (bestMatch && bestScore >= 0.85) {
        return { duplicate: true, record: bestMatch, id: bestMatch.id, matchScore: bestScore, confidence: bestScore >= 0.95 ? 'very_high' : 'high' };
      }
    }
    return { duplicate: false, matchScore: 0 };
  } catch (error) {
    console.error('Company check failed:', error);
    return { duplicate: false, matchScore: 0, error: error.message };
  }
};

if (normalized.email) {
  result.person = await checkDuplicatePerson(normalized.email);
  if (result.person.duplicate) result.hasDuplicates = true;
}
if (normalized.company && normalized.company !== 'Unknown Company') {
  result.company = await checkDuplicateCompany(normalized.company);
  if (result.company.duplicate) result.hasDuplicates = true;
}
if (!result.hasDuplicates) {
  result.action = 'create';
} else if (result.person.duplicate && result.company.duplicate) {
  result.action = 'merge_both';
} else if (result.person.duplicate) {
  result.action = 'merge_person';
} else if (result.company.duplicate) {
  result.action = 'merge_company';
}
return [{ json: result }];

// Prepare Person Data
const input = $input.first().json;
const data = input.data;
if (input.person.duplicate && input.person.id) {
  return [{ json: { personId: input.person.id, created: false, existing: true, record: input.person.record } }];
}
const personData = {
  name: { firstName: data.firstName, lastName: data.lastName },
  emails: [{ email: data.email, isPrimary: true }],
  jobTitle: data.jobTitle || undefined
};
if (data.phone) {
  personData.phones = [{ number: data.phone, isPrimary: true }];
}
return [{ json: { personData: personData, personId: null, created: false, existing: false } }];

// Prepare Company Data
const input = $input.first().json;
const data = input.data;
if (input.company.duplicate && input.company.id) {
  return [{ json: { companyId: input.company.id, created: false, existing: true, matchScore: input.company.matchScore, record: input.company.record } }];
}
const companyData = { name: data.company, domainName: data.email?.split('@')[1] || undefined };
return [{ json: { companyData: companyData, companyId: null, created: false, existing: false } }];

// Extract IDs and Prepare Note Data
const inputs = $input.all();
const personInput = inputs[0].json;
